<?php namespace App\Traits; use Illuminate\Http\Request; use Illuminate\Support\Facades\Validator; use Illuminate\Validation\ValidationException; use App\Http\Responses\ApiResponseFormatter; trait RequestValidator { protected function validateRequest(Request $request, array $rules, array $messages = [], array $customAttributes = []) { $validator = Validator::make($request->all(), $rules, $messages, $customAttributes); if ($validator->fails()) { return ApiResponseFormatter::error(trans('validation.failed'), 422, $validator->errors()->toArray()); } return $validator->validated(); } }